    private void Cases() {

        if (Input is null) throw new ArgumentNullException();

        if (Input.Length <= 1) throw new InvalidDataException();

    }

    public void Naive(){
        Cases();
        for (int i = 0; i < Input!.Length; i++) {
            for (int j = i + 1; j < Input!.Length; j++) {
                if (Input![i] + Input![j] == 0) {
                    Output![0] = Input![i];
                    Output![1] = Input![j];
                    Done = true;
                    return;
                }
            }
        }
    }

    public void Proper(){

        Cases();        
        int sum = 0, left = 0, right = Input!.Length - 1;

        while (left < right) {
            sum = Input![left] + Input![right];
            if (sum == 0) {
                Output![0] = Input![left];
                Output![1] = Input![right];
                return;
            }
            else if (sum > 0)   right--;
            else                left++;
        }

    }

